fn expect_support(candidate: &str, fixture_id: &str, expected: Support, actual: Probe) {
    match expected {
        Support::Yes => assert_eq!(
            actual,
            Probe::Pass,
            "{candidate} should decode fixture {fixture_id}"
        ),
        Support::No => assert_ne!(
            actual,
            Probe::Pass,
            "{candidate} unexpectedly decoded fixture {fixture_id}; update the report matrix"
        ),
        Support::Partial | Support::Excluded => {
            panic!("ASN.1 fixture expectations must be yes/no for {candidate} {fixture_id}")
        }
    }
}

#[test]
fn rasn_kerberos_decodes_expected_gokrb5_asn1_fixtures() {
    for fixture in ASN1_FIXTURES {
        let bytes = hex::decode(fixture_hex(fixture.id)).expect("fixture hex is valid");
        let actual = if rasn_decode(fixture.der_type, &bytes) {
            Probe::Pass
        } else {
            Probe::Fail
        };
        expect_support("rasn-kerberos", fixture.id, fixture.rasn_kerberos, actual);
    }
}

#[test]
fn picky_krb_decodes_expected_gokrb5_asn1_fixtures() {
    for fixture in ASN1_FIXTURES {
        let bytes = hex::decode(fixture_hex(fixture.id)).expect("fixture hex is valid");
        let actual = picky_decode(fixture.der_type, &bytes);
        expect_support("picky-krb", fixture.id, fixture.picky_krb, actual);
    }
}

fn rasn_decode(der_type: DerType, bytes: &[u8]) -> bool {
    match der_type {
        DerType::Authenticator => rasn::der::decode::<rasn_kerberos::Authenticator>(bytes).is_ok(),
        DerType::Ticket => rasn::der::decode::<rasn_kerberos::Ticket>(bytes).is_ok(),
        DerType::EncTicketPart => rasn::der::decode::<rasn_kerberos::EncTicketPart>(bytes).is_ok(),
        DerType::KdcReqBody => rasn::der::decode::<rasn_kerberos::KdcReqBody>(bytes).is_ok(),
        DerType::AsReq => rasn::der::decode::<rasn_kerberos::AsReq>(bytes).is_ok(),
        DerType::TgsReq => rasn::der::decode::<rasn_kerberos::TgsReq>(bytes).is_ok(),
        DerType::AsRep => rasn::der::decode::<rasn_kerberos::AsRep>(bytes).is_ok(),
        DerType::TgsRep => rasn::der::decode::<rasn_kerberos::TgsRep>(bytes).is_ok(),
        DerType::EncTgsRepPart => rasn::der::decode::<rasn_kerberos::EncTgsRepPart>(bytes).is_ok(),
        DerType::ApReq => rasn::der::decode::<rasn_kerberos::ApReq>(bytes).is_ok(),
        DerType::ApRep => rasn::der::decode::<rasn_kerberos::ApRep>(bytes).is_ok(),
        DerType::EncApRepPart => rasn::der::decode::<rasn_kerberos::EncApRepPart>(bytes).is_ok(),
        DerType::KrbSafe => rasn::der::decode::<rasn_kerberos::KrbSafe>(bytes).is_ok(),
        DerType::KrbPriv => rasn::der::decode::<rasn_kerberos::KrbPriv>(bytes).is_ok(),
        DerType::EncKrbPrivPart => {
            rasn::der::decode::<rasn_kerberos::EncKrbPrivPart>(bytes).is_ok()
        }
        DerType::KrbCred => rasn::der::decode::<rasn_kerberos::KrbCred>(bytes).is_ok(),
        DerType::EncKrbCredPart => {
            rasn::der::decode::<rasn_kerberos::EncKrbCredPart>(bytes).is_ok()
        }
        DerType::KrbError => rasn::der::decode::<rasn_kerberos::KrbError>(bytes).is_ok(),
        DerType::AuthorizationData => {
            rasn::der::decode::<rasn_kerberos::AuthorizationData>(bytes).is_ok()
        }
        DerType::TypedData => rasn::der::decode::<rasn_kerberos::TypedData>(bytes).is_ok(),
        DerType::PaEncTsEnc => rasn::der::decode::<rasn_kerberos::PaEncTsEnc>(bytes).is_ok(),
        DerType::EncryptedData => rasn::der::decode::<rasn_kerberos::EncryptedData>(bytes).is_ok(),
    }
}

fn picky_decode(der_type: DerType, bytes: &[u8]) -> Probe {
    let pass = match der_type {
        DerType::Authenticator => {
            picky_asn1_der::from_bytes::<picky_krb::data_types::Authenticator>(bytes).is_ok()
        }
        DerType::Ticket => {
            picky_asn1_der::from_bytes::<picky_krb::data_types::Ticket>(bytes).is_ok()
        }
        DerType::EncTicketPart => {
            picky_asn1_der::from_bytes::<picky_krb::data_types::EncTicketPart>(bytes).is_ok()
        }
        DerType::KdcReqBody => {
            picky_asn1_der::from_bytes::<picky_krb::messages::KdcReqBody>(bytes).is_ok()
        }
        DerType::AsReq => picky_asn1_der::from_bytes::<picky_krb::messages::AsReq>(bytes).is_ok(),
        DerType::TgsReq => picky_asn1_der::from_bytes::<picky_krb::messages::TgsReq>(bytes).is_ok(),
        DerType::AsRep => picky_asn1_der::from_bytes::<picky_krb::messages::AsRep>(bytes).is_ok(),
        DerType::TgsRep => picky_asn1_der::from_bytes::<picky_krb::messages::TgsRep>(bytes).is_ok(),
        DerType::EncTgsRepPart => {
            picky_asn1_der::from_bytes::<picky_krb::messages::EncTgsRepPart>(bytes).is_ok()
        }
        DerType::ApReq => picky_asn1_der::from_bytes::<picky_krb::messages::ApReq>(bytes).is_ok(),
        DerType::ApRep => picky_asn1_der::from_bytes::<picky_krb::messages::ApRep>(bytes).is_ok(),
        DerType::EncApRepPart => {
            picky_asn1_der::from_bytes::<picky_krb::data_types::EncApRepPart>(bytes).is_ok()
        }
        DerType::KrbPriv => {
            picky_asn1_der::from_bytes::<picky_krb::messages::KrbPriv>(bytes).is_ok()
        }
        DerType::EncKrbPrivPart => {
            picky_asn1_der::from_bytes::<picky_krb::data_types::EncKrbPrivPart>(bytes).is_ok()
        }
        DerType::KrbError => {
            picky_asn1_der::from_bytes::<picky_krb::messages::KrbError>(bytes).is_ok()
        }
        DerType::AuthorizationData => {
            picky_asn1_der::from_bytes::<picky_krb::data_types::AuthorizationData>(bytes).is_ok()
        }
        DerType::PaEncTsEnc => {
            picky_asn1_der::from_bytes::<picky_krb::data_types::PaEncTsEnc>(bytes).is_ok()
        }
        DerType::EncryptedData => {
            picky_asn1_der::from_bytes::<picky_krb::data_types::EncryptedData>(bytes).is_ok()
        }
        DerType::KrbSafe | DerType::KrbCred | DerType::EncKrbCredPart | DerType::TypedData => {
            return Probe::Unsupported;
        }
    };

    if pass { Probe::Pass } else { Probe::Fail }
}
